public class QuebraVigenere {
	private static final String CRIPTOGRAMA = "";

	public static void main(String[] args) {
		for (int tamanhoChave = 1 ; tamanhoChave <= 30 ; tamanhoChave++) {//Tentativa de adivinhar o tamanho da senha do usuário
			System.out.println("===========================================");
			System.out.println("Testando chave de tamanho" + tamanhoChave);
			
			for (int numeroConjunto = 0 ; numeroConjunto < tamanhoChave ; numeroConjunto++) {
				int[] vetorOcorrencia = new int[256];
				int maiorQuantidade = 0;
				int maiorLetra = 0;
				
				for (int i = 0 ; i < CRIPTOGRAMA.length() ; i+=2) {//Selenionando a posição correta dependendo do numero do conjunto
					if (((i/2) % tamanhoChave) == numeroConjunto) {
						int letra = Integer.parseInt(CRIPTOGRAMA.substring(i, i + 2), 16);
						vetorOcorrencia[letra]++;
						if (vetorOcorrencia[letra] > maiorQuantidade) {
							maiorQuantidade = vetorOcorrencia[letra];
							maiorLetra = letra;
						}
					}
				}
				System.out.print((char) (maiorLetra ^32));
			}
			System.out.println();
		}
	}
}
